import { queryAll, queryOne } from './database.js';
import { marked } from './vendor/marked.min.js';
import Prism from './vendor/prism.min.js';
import DOMPurify from './vendor/purify.min.js';

// DOMPurify configuration (matching bv)
const SANITIZE_CONFIG = {
    ALLOWED_TAGS: ['p', 'br', 'strong', 'em', 'code', 'pre', 'ul', 'ol', 'li', 
                   'a', 'h1', 'h2', 'h3', 'h4', 'blockquote', 'mark', 'span'],
    ALLOWED_ATTR: ['href', 'title', 'class', 'data-language'],
    ALLOW_DATA_ATTR: false,
    FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed', 'form'],
    FORBID_ATTR: ['onerror', 'onclick', 'onload', 'onmouseover'],
};

export class ConversationViewer {
    constructor(container) {
        this.container = container;
        this.currentConvId = null;
    }

    async load(conversationId, highlightMessageId = null) {
        this.currentConvId = conversationId;

        // Load conversation metadata
        const conv = queryOne(`
            SELECT id, agent, workspace, title, started_at, ended_at, message_count
            FROM conversations WHERE id = ?
        `, [conversationId]);

        if (!conv) {
            this.showError('Conversation not found');
            return;
        }

        // Load messages
        const messages = queryAll(`
            SELECT id, role, content, created_at
            FROM messages
            WHERE conversation_id = ?
            ORDER BY idx ASC
        `, [conversationId]);

        this.render(conv, messages, highlightMessageId);
    }

    render(conv, messages, highlightId) {
        const formattedDate = formatDate(conv.started_at);

        this.container.innerHTML = `
            <div class="conversation-view">
                <header class="conv-header">
                    <button id="back-btn" class="back-button">← Back</button>
                    <div class="conv-meta">
                        <h1>${escapeHtml(conv.title || 'Untitled Conversation')}</h1>
                        <div class="conv-details">
                            <span class="agent-badge">${conv.agent}</span>
                            <span>${formattedDate}</span>
                            <span>${conv.message_count} messages</span>
                        </div>
                        <div class="conv-workspace">${escapeHtml(conv.workspace || '')}</div>
                    </div>
                </header>

                <div class="messages-container" id="messages-container">
                    ${messages.map(m => this.renderMessage(m, m.id === highlightId)).join('')}
                </div>
            </div>
        `;

        // Bind back button
        this.container.querySelector('#back-btn').addEventListener('click', () => {
            window.dispatchEvent(new CustomEvent('navigate', { detail: { view: 'search' } }));
        });

        // Apply syntax highlighting
        this.highlightCode();

        // Scroll to highlighted message
        if (highlightId) {
            const el = this.container.querySelector(`[data-message-id="${highlightId}"]`);
            if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }

    renderMessage(message, highlighted = false) {
        const roleClass = message.role === 'user' ? 'user-message' : 
                          message.role === 'assistant' ? 'assistant-message' : 
                          'system-message';
        const highlightClass = highlighted ? 'highlighted' : '';

        // Render markdown
        const html = marked.parse(message.content);

        // Sanitize HTML
        const safeHtml = DOMPurify.sanitize(html, SANITIZE_CONFIG);

        return `
            <div class="message ${roleClass} ${highlightClass}" 
                 data-message-id="${message.id}">
                <div class="message-header">
                    <span class="role-label">${capitalize(message.role)}</span>
                    <span class="message-time">${formatTime(message.created_at)}</span>
                </div>
                <div class="message-content">${safeHtml}</div>
            </div>
        `;
    }

    highlightCode() {
        // Find all code blocks and apply Prism
        this.container.querySelectorAll('pre code').forEach(block => {
            // Detect language from class
            const match = block.className.match(/language-(\w+)/);
            const lang = match ? match[1] : 'plaintext';

            if (Prism.languages[lang]) {
                block.innerHTML = Prism.highlight(
                    block.textContent,
                    Prism.languages[lang],
                    lang
                );
            }
        });
    }

    showError(message) {
        this.container.innerHTML = `
            <div class="error-view">
                <h2>Error</h2>
                <p>${escapeHtml(message)}</p>
                <button id="back-btn">← Back to Search</button>
            </div>
        `;
        this.container.querySelector('#back-btn').addEventListener('click', () => {
            window.dispatchEvent(new CustomEvent('navigate', { detail: { view: 'search' } }));
        });
    }
}

// Helpers
function escapeHtml(str) {
    return str.replace(/[&<>"']/g, c => ({
        '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;'
    }[c]));
}

function capitalize(str) {
    return str.charAt(0).toUpperCase() + str.slice(1);
}

function formatDate(ts) {
    return new Date(ts).toLocaleDateString('en-US', {
        year: 'numeric', month: 'short', day: 'numeric'
    });
}

function formatTime(ts) {
    return new Date(ts).toLocaleTimeString('en-US', {
        hour: '2-digit', minute: '2-digit'
    });
}
```

