```javascript
// Hash-based routing for direct message links
// #/c/123        → conversation 123
// #/c/123/m/456  → message 456 in conversation 123

class Router {
    constructor(onRoute) {
        this.onRoute = onRoute;
        window.addEventListener('hashchange', () => this.route());
        this.route();
    }

    route() {
        const hash = window.location.hash.slice(1);
        const parts = hash.split('/').filter(Boolean);

        if (parts[0] === 'c' && parts[1]) {
            const convId = parseInt(parts[1], 10);
            const msgId = parts[2] === 'm' ? parseInt(parts[3], 10) : null;
            this.onRoute({ view: 'conversation', convId, msgId });
        } else if (parts[0] === 'search' && parts[1]) {
            this.onRoute({ view: 'search', query: decodeURIComponent(parts[1]) });
        } else {
            this.onRoute({ view: 'search' });
        }
    }

    navigate(path) {
        window.location.hash = path;
    }
}
```

